#include <bits/stdc++.h>
#define x first
#define y second
using namespace std;

const int N=1e5+10;

struct Node{
    int son[26],fail;
}tr[N];

int n,m,tot=1,path[N],cnt,w[N],ans[N];
int q[N],dfn[N],num,sz[N],c[N];
char s[N];
vector<pair<int,int>> qs[N];
vector<int> e[N];

void add(int x,int k){
    for(;x<=tot;x+=(x&(-x)))
        c[x]+=k;
}

int ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

void dfs(int x){
    dfn[x]=++num,sz[x]=1;
    for(int y:e[x]){
        dfs(y);
        sz[x]+=sz[y];
    }
}

void build(){
    int p=1;
    path[0]=1;
    for(int i=0;s[i];i++){
        if('a'<=s[i] && s[i]<='z'){
            if(!tr[p].son[s[i]-'a'])
                tr[p].son[s[i]-'a']=++tot;
            p=tr[p].son[s[i]-'a'];
            path[++cnt]=p;
        }else if(s[i]=='B')
            p=path[--cnt];
        else
            w[++n]=p;
    }
    int hh=1,tt=0;
    tr[1].fail=1;
    for(int i=0;i<26;i++)
        if(tr[1].son[i]){
            tr[tr[1].son[i]].fail=1;
            q[++tt]=tr[1].son[i];
        }else
            tr[1].son[i]=1;
    while(hh<=tt){
        int x=q[hh++];
        e[tr[x].fail].push_back(x);
        for(int i=0;i<26;i++)
            if(tr[x].son[i]){
                tr[tr[x].son[i]].fail=tr[tr[x].fail].son[i];
                q[++tt]=tr[x].son[i];
            }else
                tr[x].son[i]=tr[tr[x].fail].son[i];
    }
    dfs(1);
}

void solve(){
    int sum=0,p=1;
    cnt=0,path[cnt]=1;
    for(int i=0;s[i];i++){
        if('a'<=s[i] && s[i]<='z'){
            p=tr[p].son[s[i]-'a'];
            path[++cnt]=p;
            add(dfn[p],1);
        }else if(s[i]=='B'){
            add(dfn[p],-1);
            p=path[--cnt];
        }else{
            sum++;
            for(pair<int,int> j:qs[sum])
                ans[j.y]=ask(dfn[w[j.x]]+sz[w[j.x]]-1)-ask(dfn[w[j.x]]-1);
        }
    }
    for(int i=1;i<=m;i++)
        printf("%d\n",ans[i]);
}

int main(){
    scanf("%s",s);
    build();
    scanf("%d",&m);
    for(int i=1,u,v;i<=m;i++){
        scanf("%d%d",&u,&v);
        qs[v].push_back(make_pair(u,i));
    }
    solve();
    return 0;
}
